{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.org/schemas/directory-health-report.schema.json",
  "title": "DirectoryHealthReport",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "schema_version",
    "generated_utc",
    "scan",
    "summary",
    "rollups_by_dir",
    "anomalies",
    "compliance",
    "snapshot_signature"
  ],
  "properties": {
    "schema_version": {
      "type": "string",
      "pattern": "^[0-9]+\\.[0-9]+\\.[0-9]+$",
      "description": "Schema version for this report structure."
    },
    "generated_utc": {
      "type": "string",
      "format": "date-time"
    },
    "scan": {
      "$ref": "#/$defs/ScanContext"
    },
    "summary": {
      "$ref": "#/$defs/DirectorySummary"
    },
    "rollups_by_dir": {
      "$ref": "#/$defs/RollupsByDir"
    },
    "anomalies": {
      "type": "array",
      "items": { "$ref": "#/$defs/Anomaly" }
    },
    "compliance": {
      "type": "array",
      "items": { "$ref": "#/$defs/ComplianceItem" }
    },
    "snapshot_signature": {
      "$ref": "#/$defs/SnapshotSignature"
    }
  },
  "$defs": {
    "ScanContext": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "scan_id",
        "scan_root",
        "tool",
        "started_utc",
        "finished_utc",
        "duration_ms"
      ],
      "properties": {
        "scan_id": {
          "type": "string",
          "minLength": 1,
          "description": "Unique identifier for this scan run."
        },
        "scan_root": {
          "type": "string",
          "minLength": 1,
          "description": "Absolute root path that was scanned."
        },
        "platform": {
          "type": "object",
          "additionalProperties": false,
          "properties": {
            "os_name": { "type": "string" },
            "os_version": { "type": "string" },
            "fs_type": { "type": "string" },
            "hostname": { "type": "string" },
            "username": { "type": "string" },
            "timezone": { "type": "string" }
          }
        },
        "tool": {
          "type": "object",
          "additionalProperties": false,
          "required": ["name", "version"],
          "properties": {
            "name": { "type": "string" },
            "version": { "type": "string" },
            "build": { "type": "string" },
            "config": {
              "type": "object",
              "additionalProperties": true,
              "description": "Tool configuration used for the scan. Free-form to avoid schema churn."
            }
          }
        },
        "started_utc": { "type": "string", "format": "date-time" },
        "finished_utc": { "type": "string", "format": "date-time" },
        "duration_ms": { "type": "integer", "minimum": 0 }
      }
    },

    "DirectorySummary": {
      "type": "object",
      "additionalProperties": false,
      "required": ["pass_a", "pass_b", "pass_c"],
      "properties": {
        "pass_a": { "$ref": "#/$defs/PassA_Metrics" },
        "pass_b": { "$ref": "#/$defs/PassB_Metrics" },
        "pass_c": { "$ref": "#/$defs/PassC_Metrics" }
      }
    },

    "RollupsByDir": {
      "type": "object",
      "additionalProperties": false,
      "required": ["rollup_unit", "items"],
      "properties": {
        "rollup_unit": {
          "type": "string",
          "enum": ["directory"],
          "description": "Rollups are per-directory aggregates."
        },
        "items": {
          "type": "array",
          "items": { "$ref": "#/$defs/DirectoryRollup" }
        }
      }
    },

    "DirectoryRollup": {
      "type": "object",
      "additionalProperties": false,
      "required": ["relative_dir", "depth", "pass_a", "pass_b", "pass_c"],
      "properties": {
        "relative_dir": {
          "type": "string",
          "description": "Directory path relative to scan_root. Use '.' for the root."
        },
        "depth": {
          "type": "integer",
          "minimum": 0,
          "description": "Depth of this directory relative to scan_root. Root is 0."
        },
        "pass_a": { "$ref": "#/$defs/PassA_Metrics" },
        "pass_b": { "$ref": "#/$defs/PassB_Metrics" },
        "pass_c": { "$ref": "#/$defs/PassC_Metrics" }
      }
    },

    "Anomaly": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "severity", "pass", "code", "title", "description"],
      "properties": {
        "id": {
          "type": "string",
          "minLength": 1,
          "description": "Unique anomaly id within the report."
        },
        "severity": {
          "type": "string",
          "enum": ["info", "low", "medium", "high", "critical"]
        },
        "pass": {
          "type": "string",
          "enum": ["pass_a", "pass_b", "pass_c"]
        },
        "code": {
          "type": "string",
          "minLength": 1,
          "description": "Stable anomaly code (e.g., PATH_TOO_LONG, SSOT_ID_COLLISION, SECRET_PATTERN_FOUND)."
        },
        "title": { "type": "string", "minLength": 1 },
        "description": { "type": "string", "minLength": 1 },
        "relative_path": {
          "type": "string",
          "description": "Optional file/dir path relative to scan_root that triggered the anomaly."
        },
        "metric_ref": {
          "type": "string",
          "description": "Optional JSON pointer-like reference to the metric (e.g., '/summary/pass_a/filesystem_hygiene/path_length_risk')."
        },
        "observed": {
          "type": ["object", "array", "string", "number", "integer", "boolean", "null"],
          "description": "Observed value(s) relevant to the anomaly."
        },
        "expected": {
          "type": ["object", "array", "string", "number", "integer", "boolean", "null"],
          "description": "Expected value(s) or threshold."
        },
        "recommendation": { "type": "string" },
        "evidence": {
          "type": "object",
          "additionalProperties": true,
          "description": "Free-form evidence details (e.g., sample offending paths, matched patterns)."
        }
      }
    },

    "ComplianceItem": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "pass", "policy", "metric", "status"],
      "properties": {
        "id": { "type": "string", "minLength": 1 },
        "pass": { "type": "string", "enum": ["pass_a", "pass_b", "pass_c"] },
        "policy": {
          "type": "string",
          "minLength": 1,
          "description": "Policy name (e.g., SSOT_ID_FORMAT, NAMING_CONVENTION, EXTENSION_CONTENT_MATCH)."
        },
        "metric": {
          "type": "string",
          "minLength": 1,
          "description": "What is being measured (e.g., 'ssot_id_coverage', 'naming_convention_compliance')."
        },
        "scope": {
          "type": "string",
          "description": "Optional scope label (e.g., 'global', 'per_dir', 'src_only')."
        },
        "status": {
          "type": "string",
          "enum": ["pass", "warn", "fail", "unknown"]
        },
        "percent": {
          "type": "number",
          "minimum": 0,
          "maximum": 100
        },
        "counts": {
          "type": "object",
          "additionalProperties": false,
          "properties": {
            "numerator": { "type": "integer", "minimum": 0 },
            "denominator": { "type": "integer", "minimum": 0 }
          }
        },
        "details": {
          "type": "object",
          "additionalProperties": true
        }
      }
    },

    "SnapshotSignature": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "signature_version",
        "canonicalization",
        "algorithm",
        "included_fields",
        "record_count",
        "digest_hex"
      ],
      "properties": {
        "signature_version": {
          "type": "string",
          "pattern": "^[0-9]+\\.[0-9]+\\.[0-9]+$"
        },
        "canonicalization": {
          "type": "object",
          "additionalProperties": false,
          "required": ["path_separator", "sort_order", "normalization"],
          "properties": {
            "path_separator": { "type": "string", "enum": ["/"] },
            "sort_order": {
              "type": "string",
              "enum": ["lexicographic_utf8"],
              "description": "How records are sorted before hashing."
            },
            "normalization": {
              "type": "string",
              "enum": ["none", "unicode_nfc", "unicode_nfd"],
              "description": "Optional path/name normalization applied before signature."
            }
          }
        },
        "algorithm": {
          "type": "string",
          "enum": ["sha256"],
          "description": "Digest algorithm for snapshot signature."
        },
        "included_fields": {
          "type": "array",
          "minItems": 1,
          "items": {
            "type": "string",
            "enum": [
              "relative_path",
              "is_dir",
              "size_bytes",
              "mtime_utc",
              "content_hash"
            ]
          },
          "description": "Fields used to build signature records. If 'content_hash' is included, it implies deep hashing was enabled."
        },
        "record_count": { "type": "integer", "minimum": 0 },
        "digest_hex": {
          "type": "string",
          "pattern": "^[a-f0-9]{64}$"
        },
        "records_spec": {
          "type": "string",
          "description": "Human-readable spec of signature record format (e.g., 'relative_path|is_dir|size_bytes|mtime_utc|content_hash')."
        },
        "previous": {
          "type": "object",
          "additionalProperties": false,
          "properties": {
            "digest_hex": { "type": "string", "pattern": "^[a-f0-9]{64}$" },
            "generated_utc": { "type": "string", "format": "date-time" }
          }
        },
        "comparison": {
          "type": "object",
          "additionalProperties": false,
          "properties": {
            "status": { "type": "string", "enum": ["same", "different", "unknown"] },
            "added_paths": { "type": "integer", "minimum": 0 },
            "removed_paths": { "type": "integer", "minimum": 0 },
            "modified_paths": { "type": "integer", "minimum": 0 }
          }
        }
      }
    },

    "PassA_Metrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "volume_inventory",
        "storage_size",
        "temporal_activity",
        "structure_navigation",
        "filesystem_hygiene",
        "permissions_ownership",
        "repo_automation_signals",
        "dependency_environment",
        "duplication_redundancy",
        "integrity_compliance",
        "quality_of_life"
      ],
      "properties": {
        "volume_inventory": { "$ref": "#/$defs/VolumeInventoryMetrics" },
        "storage_size": { "$ref": "#/$defs/StorageSizeMetrics" },
        "temporal_activity": { "$ref": "#/$defs/TemporalActivityMetrics" },
        "structure_navigation": { "$ref": "#/$defs/StructureNavigationMetrics" },
        "filesystem_hygiene": { "$ref": "#/$defs/FilesystemHygieneRiskMetrics" },
        "permissions_ownership": { "$ref": "#/$defs/PermissionsOwnershipMetrics" },
        "repo_automation_signals": { "$ref": "#/$defs/RepoAutomationSignalsMetrics" },
        "dependency_environment": { "$ref": "#/$defs/DependencyEnvironmentMetrics" },
        "duplication_redundancy": { "$ref": "#/$defs/DuplicationRedundancy_MetadataOnlyMetrics" },
        "integrity_compliance": { "$ref": "#/$defs/IntegrityCompliance_MetadataOnlyMetrics" },
        "quality_of_life": { "$ref": "#/$defs/QualityOfLife_MetadataOnlyMetrics" }
      }
    },

    "PassB_Metrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "content_quality_light",
        "content_sensitivity_light",
        "linkage_reference_integrity_light",
        "integrity_compliance_light"
      ],
      "properties": {
        "content_quality_light": { "$ref": "#/$defs/ContentQualityLightMetrics" },
        "content_sensitivity_light": { "$ref": "#/$defs/ContentSensitivitySecretRiskLightMetrics" },
        "linkage_reference_integrity_light": { "$ref": "#/$defs/LinkageReferenceIntegrityLightMetrics" },
        "integrity_compliance_light": { "$ref": "#/$defs/IntegrityCompliance_LightContentMetrics" }
      }
    },

    "PassC_Metrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "duplication_redundancy_deep",
        "content_sensitivity_deep",
        "linkage_reference_integrity_deep",
        "governance_ssot",
        "change_dynamics"
      ],
      "properties": {
        "duplication_redundancy_deep": { "$ref": "#/$defs/DuplicationRedundancy_DeepMetrics" },
        "content_sensitivity_deep": { "$ref": "#/$defs/ContentSensitivitySecretRiskDeepMetrics" },
        "linkage_reference_integrity_deep": { "$ref": "#/$defs/LinkageReferenceIntegrityDeepMetrics" },
        "governance_ssot": { "$ref": "#/$defs/GovernanceSSOTMetrics" },
        "change_dynamics": { "$ref": "#/$defs/ChangeDynamicsMetrics" }
      }
    },

    "VolumeInventoryMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "total_file_count",
        "total_dir_count",
        "root_folder_count",
        "total_subfolder_count",
        "file_type_distribution"
      ],
      "properties": {
        "total_file_count": { "type": "integer", "minimum": 0 },
        "total_dir_count": { "type": "integer", "minimum": 0 },
        "root_folder_count": { "type": "integer", "minimum": 0 },
        "total_subfolder_count": { "type": "integer", "minimum": 0 },
        "file_type_distribution": {
          "type": "object",
          "additionalProperties": false,
          "patternProperties": {
            "^(\\.[A-Za-z0-9]{1,16}|NOEXT)$": { "type": "integer", "minimum": 0 }
          }
        }
      }
    },

    "StorageSizeMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "total_directory_size_bytes",
        "largest_files"
      ],
      "properties": {
        "total_directory_size_bytes": { "type": "integer", "minimum": 0 },
        "file_size_outliers": {
          "type": "array",
          "items": { "$ref": "#/$defs/PathSizeEntry" },
          "description": "Files significantly larger than average; selection criteria is tool-defined."
        },
        "largest_files": {
          "type": "array",
          "items": { "$ref": "#/$defs/PathSizeEntry" },
          "description": "Top-N largest files."
        }
      }
    },

    "TemporalActivityMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "last_modified_spread",
        "stale_file_count",
        "creation_bursts"
      ],
      "properties": {
        "last_modified_spread": {
          "type": "object",
          "additionalProperties": false,
          "required": ["oldest_mtime_utc", "newest_mtime_utc"],
          "properties": {
            "oldest_mtime_utc": { "type": "string", "format": "date-time" },
            "newest_mtime_utc": { "type": "string", "format": "date-time" }
          }
        },
        "stale_file_count": {
          "type": "object",
          "additionalProperties": false,
          "required": ["threshold_days", "count"],
          "properties": {
            "threshold_days": { "type": "integer", "minimum": 1 },
            "count": { "type": "integer", "minimum": 0 }
          }
        },
        "creation_bursts": {
          "type": "array",
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": ["window_start_utc", "window_end_utc", "created_files"],
            "properties": {
              "window_start_utc": { "type": "string", "format": "date-time" },
              "window_end_utc": { "type": "string", "format": "date-time" },
              "created_files": { "type": "integer", "minimum": 0 },
              "notes": { "type": "string" }
            }
          },
          "description": "Tool-defined burst windows (e.g., hourly/daily buckets) where many files were created."
        }
      }
    },

    "StructureNavigationMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "maximum_nesting_depth",
        "average_files_per_folder",
        "empty_folders",
        "symlinks_and_broken_paths"
      ],
      "properties": {
        "maximum_nesting_depth": { "type": "integer", "minimum": 0 },
        "average_files_per_folder": { "type": "number", "minimum": 0 },
        "empty_folders": { "type": "integer", "minimum": 0 },
        "symlinks_and_broken_paths": {
          "type": "object",
          "additionalProperties": false,
          "required": ["symlink_count", "broken_link_count"],
          "properties": {
            "symlink_count": { "type": "integer", "minimum": 0 },
            "broken_link_count": { "type": "integer", "minimum": 0 },
            "samples_broken": {
              "type": "array",
              "items": { "type": "string" }
            }
          }
        }
      }
    },

    "FilesystemHygieneRiskMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "path_length_risk",
        "invalid_problematic_names",
        "case_collision_risk",
        "unicode_normalization_issues",
        "illegal_suspicious_characters"
      ],
      "properties": {
        "path_length_risk": {
          "type": "object",
          "additionalProperties": false,
          "required": ["threshold_chars", "count_exceeding", "max_path_length", "top_offenders"],
          "properties": {
            "threshold_chars": { "type": "integer", "minimum": 1 },
            "count_exceeding": { "type": "integer", "minimum": 0 },
            "max_path_length": { "type": "integer", "minimum": 0 },
            "top_offenders": {
              "type": "array",
              "items": { "$ref": "#/$defs/PathLengthEntry" }
            }
          }
        },
        "invalid_problematic_names": {
          "type": "object",
          "additionalProperties": false,
          "required": ["reserved_names_count", "trailing_dot_space_count", "control_char_count", "samples"],
          "properties": {
            "reserved_names_count": { "type": "integer", "minimum": 0 },
            "trailing_dot_space_count": { "type": "integer", "minimum": 0 },
            "control_char_count": { "type": "integer", "minimum": 0 },
            "samples": { "type": "array", "items": { "type": "string" } }
          }
        },
        "case_collision_risk": {
          "type": "object",
          "additionalProperties": false,
          "required": ["collision_groups_count", "collision_groups_samples"],
          "properties": {
            "collision_groups_count": { "type": "integer", "minimum": 0 },
            "collision_groups_samples": {
              "type": "array",
              "items": { "$ref": "#/$defs/CollisionGroup" }
            }
          }
        },
        "unicode_normalization_issues": {
          "type": "object",
          "additionalProperties": false,
          "required": ["issue_groups_count", "issue_groups_samples"],
          "properties": {
            "issue_groups_count": { "type": "integer", "minimum": 0 },
            "issue_groups_samples": {
              "type": "array",
              "items": { "$ref": "#/$defs/CollisionGroup" }
            }
          }
        },
        "illegal_suspicious_characters": {
          "type": "object",
          "additionalProperties": false,
          "required": ["character_counts"],
          "properties": {
            "character_counts": {
              "type": "object",
              "additionalProperties": false,
              "patternProperties": {
                "^.$": { "type": "integer", "minimum": 0 }
              }
            }
          }
        }
      }
    },

    "PermissionsOwnershipMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "ownership_distribution",
        "acl_permissions_anomalies",
        "executable_surface_area",
        "hidden_system_attributes",
        "recent_permission_changes"
      ],
      "properties": {
        "ownership_distribution": {
          "type": "object",
          "additionalProperties": false,
          "required": ["top_owners", "top_groups", "orphaned_ownership_count"],
          "properties": {
            "top_owners": { "type": "array", "items": { "$ref": "#/$defs/KeyCountEntry" } },
            "top_groups": { "type": "array", "items": { "$ref": "#/$defs/KeyCountEntry" } },
            "orphaned_ownership_count": { "type": "integer", "minimum": 0 }
          }
        },
        "acl_permissions_anomalies": {
          "type": "object",
          "additionalProperties": false,
          "required": ["world_writable_count", "broken_inheritance_count", "samples"],
          "properties": {
            "world_writable_count": { "type": "integer", "minimum": 0 },
            "broken_inheritance_count": { "type": "integer", "minimum": 0 },
            "samples": { "type": "array", "items": { "type": "string" } }
          }
        },
        "executable_surface_area": {
          "type": "object",
          "additionalProperties": false,
          "required": ["executable_count", "by_extension"],
          "properties": {
            "executable_count": { "type": "integer", "minimum": 0 },
            "by_extension": {
              "type": "object",
              "additionalProperties": false,
              "patternProperties": {
                "^\\.[A-Za-z0-9]{1,16}$": { "type": "integer", "minimum": 0 }
              }
            }
          }
        },
        "hidden_system_attributes": {
          "type": "object",
          "additionalProperties": false,
          "required": ["hidden_count", "system_count", "read_only_count"],
          "properties": {
            "hidden_count": { "type": "integer", "minimum": 0 },
            "system_count": { "type": "integer", "minimum": 0 },
            "read_only_count": { "type": "integer", "minimum": 0 }
          }
        },
        "recent_permission_changes": {
          "type": "object",
          "additionalProperties": false,
          "required": ["supported", "notes"],
          "properties": {
            "supported": { "type": "boolean" },
            "notes": { "type": "string" }
          },
          "description": "Requires historical baseline or OS auditing; may be unsupported."
        }
      }
    },

    "RepoAutomationSignalsMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "vcs_presence_hygiene",
        "dirty_working_tree_indicators",
        "build_artifact_detection",
        "ci_cd_configuration_coverage"
      ],
      "properties": {
        "vcs_presence_hygiene": {
          "type": "object",
          "additionalProperties": false,
          "required": ["git_present", "nested_repo_count", "submodule_present", "gitignore_coverage_percent"],
          "properties": {
            "git_present": { "type": "boolean" },
            "nested_repo_count": { "type": "integer", "minimum": 0 },
            "submodule_present": { "type": "boolean" },
            "gitignore_coverage_percent": { "type": "number", "minimum": 0, "maximum": 100 }
          }
        },
        "dirty_working_tree_indicators": {
          "type": "object",
          "additionalProperties": false,
          "required": ["supported", "untracked_count", "modified_count", "ignored_bytes"],
          "properties": {
            "supported": { "type": "boolean" },
            "untracked_count": { "type": "integer", "minimum": 0 },
            "modified_count": { "type": "integer", "minimum": 0 },
            "ignored_bytes": { "type": "integer", "minimum": 0 }
          }
        },
        "build_artifact_detection": {
          "type": "object",
          "additionalProperties": false,
          "required": ["artifact_bytes", "artifact_file_count", "artifact_to_source_ratio"],
          "properties": {
            "artifact_bytes": { "type": "integer", "minimum": 0 },
            "artifact_file_count": { "type": "integer", "minimum": 0 },
            "artifact_to_source_ratio": { "type": "number", "minimum": 0 },
            "artifact_locations_top": {
              "type": "array",
              "items": { "$ref": "#/$defs/PathSizeEntry" }
            }
          }
        },
        "ci_cd_configuration_coverage": {
          "type": "object",
          "additionalProperties": false,
          "required": ["github_workflows_present", "pipeline_config_files"],
          "properties": {
            "github_workflows_present": { "type": "boolean" },
            "pipeline_config_files": { "type": "array", "items": { "type": "string" } }
          }
        }
      }
    },

    "DependencyEnvironmentMetrics": {
      "type": "object",
      "additionalProperties": false,
      "required": ["manifest_inventory", "lockfile_completeness", "venv_vendor_detection"],
      "properties": {
        "manifest_inventory": {
          "type": "object",
          "additionalProperties": false,
          "required": ["manifests_found"],
          "properties": {
